Full disclosure -- I implemented your algorithm, not your code. And only for `XYZ` to keep it simple. Required changes are noted in the inline comments.

```js
setFromQuaternion2( q, order = this._order, update = true ) {

	// "XYZ" only
	const i = 0;
	const j = 1;
	const k = 2;
	const parity = - 1;

	const v = [ q.x, q.y, q.z ];
	let a, b, c, d;

	a = q.w - v[ j ];
	b = v[ i ] + v[ k ] * parity;
	c = v[ j ] + q.w;
	d = v[ k ] * parity - v[ i ];

	// for intrinsic, must switch i and k

	let angles = [ 0, 0, 0 ];

	// middle angle is always easy
	//angles[ 1 ] = 2 * Math.atan2( Math.hypot( c, d ), Math.hypot( a, b ) ); // scaled by 2 -- much slower
	angles[ 1 ] = Math.acos( 2 * ( a * a + b * b ) / ( a * a + b * b + c * c + d * d ) - 1 ); // changed, maybe clamp it

	const half_sum = Math.atan2( b, a );
	const half_diff = Math.atan2( d, c );
	const eps = 10E-7;

	// check if the case is degenerate
	if ( Math.abs( angles[ 1 ] ) < eps ) {

		//angles[ 2 ] = 0;
		//angles[ 0 ] = 2 * half_sum;
		angles[ 0 ] = 0;
		angles[ 2 ] = 2 * half_sum; // changed

	} else if ( Math.abs( angles[ 1 ] - Math.PI ) < eps ) {

		//angles[ 2 ] = 0;
		//angles[ 0 ] = 2 * half_diff;
		angles[ 0 ] = 0;
		angles[ 2 ] = 2 * half_diff; // changed

	} else {

		//angles[ 2 ] = half_sum - half_diff;
		//angles[ 0 ] = half_sum + half_diff;
		angles[ 0 ] = half_sum - half_diff;
		angles[ 2 ] = half_sum + half_diff; // changed

	}

	//angles[ 0 ] *= parity;
	angles[ 2 ] *= parity; // changed
	angles[ 1 ] -= Math.PI / 2;

	// making sure angles are in set [-pi, pi]
	for ( let i = 0; i < 3; i ++ ) {

		if ( angles[ i ] < - Math.PI ) {

			angles[ i ] += 2 * Math.PI;

		} else if ( angles[ i ] > Math.PI ) {

			angles[ i ] -= 2 * Math.PI;

		}

	}

	this._x = angles[ 0 ];
	this._y = angles[ 1 ];
	this._z = angles[ 2 ];

	this._order = order;

	if ( update === true ) this._onChangeCallback();

	return this;

}
